#!/usr/bin/env bash
set -euo pipefail

OPEN_SOURCE_ROOT="./open-source"
ROOT="$OPEN_SOURCE_ROOT/gnosis/distributed-inference"
IMAGE="distributed-inference/paris-probe-rknot:local"
LOG_DIR="$ROOT/probe-logs"

mkdir -p "$LOG_DIR"

cd "$OPEN_SOURCE_ROOT"

docker build -f gnosis/distributed-inference/Dockerfile.paris-probe -t "$IMAGE" .

start_probe() {
  local name="$1"
  local log_name="$2"
  shift 2

  docker rm -f "$name" >/dev/null 2>&1 || true
  docker run -d \
    --name "$name" \
    --restart unless-stopped \
    --mount "type=bind,src=$LOG_DIR,dst=/probe-logs" \
    --entrypoint /bin/bash \
    "$IMAGE" -lc "exec /work/target/release/paris-probe-rknot $* > /probe-logs/$log_name 2>&1" \
    >"$LOG_DIR/$name.container-id"
}

start_probe bigllm-gemma4 gemma4-31b-it-probe.log \
  --dense https://edgework.ai/api/v1/r2/distributed-inference/models/gemma4-31b-it.knot \
  --dense-only \
  --tokens 2,669,5279,529,7001,563 \
  --expected 9079

start_probe bigllm-qwen72 qwen2.5-72b-probe.log \
  --dense https://edgework.ai/api/v1/r2/distributed-inference/models/qwen2.5-72b-instruct.knot \
  --dense-only \
  --tokens 785,6722,315,9625,374 \
  --expected 12095

start_probe bigllm-llama70 llama-3.3-70b-probe.log \
  --dense https://edgework.ai/api/v1/r2/distributed-inference/models/llama-3.3-70b-instruct.knot \
  --dense-only \
  --tokens 791,6864,315,9822,374 \
  --expected 12366

echo "Started restartable probe containers:"
docker ps --filter 'name=bigllm-' --format '  {{.Names}}\t{{.Status}}'
